class Counter:
  def __init__(self, limit):
    self.limit = limit
    self.val = 0
  def __iter__(self):
    return self
  def __next__(self):
    if self.val >= self.limit:
      raise StopIteration
    self.val += 1
    return self.val

for num in Counter(2):
  print(num)

