challenge.solution:
class Repeater:
  def __init__(self, value, count):
    self.value = value
    self.count = count
    self.current = 0

  def __iter__(self):
    return self

  def __next__(self):
    if self.current >= self.count:
      raise StopIteration
    self.current += 1
    return self.value
